package service.impl; import service.TranslationService; import dao.PhraseDao; import dao.impl.PhraseDaoImpl; import model.Phrase; import java.util.*;
public class TranslationServiceImpl implements TranslationService{ private PhraseDao dao=new PhraseDaoImpl(); public List<Phrase> phrases(){return dao.findAll();} public void addPhrase(Phrase p){dao.create(p);} public String translate(String input,String lang){Phrase p=dao.findByChinese(input.trim()); if(lang.contains("越"))return p.getVi(); if(lang.contains("印"))return p.getIdText(); if(lang.contains("菲"))return p.getFil(); return p.getZh();}}
